//vip.opstream11.com/share/16543006525cbf0f74654bced183cffe","link_m3u8":"https://vip.opstream11.com/20231206/49761_8a38cb3d/index.m3u8"}]}],"description":"Doom Patrol là loạt phim truyền hình web của Mỹ được tạo bởi Jeremy Carver cho DC Universe. Dựa trên nhóm siêu anh hùng cùng tên của DC Comics, bộ truyện có Jane, Rita Farr, Vic Stone, Larry Trainor, Cliff Steele, và Chief là thành viên của Doom Patrol. Lấy bối cảnh năm 2019, nhóm Doom Patrol - bao gồm Robotman, Negative Man, Elasti-Woman, Crazy Jane cùng thành viên mới Cyborg dưới sự dẫn dắt của Dr. Niles Caulder - nhận nhiệm vụ bảo vệ thế giới khỏi kẻ thù nguy hiểm tên là Mr. Nobody.","tmdb_id":79501,"_supabaseOriginalSlug":"biet-doi-diet-vong-phan-4","_supabaseExportEpisodesOnly":false,"_id":"6562fe6503f63c57cbb0704a","time":"49 phút/tập","tmdb":{"type":"tv","id":"79501","season":4,"vote_average":7.539,"vote_count":1402},"_image_preserved":true},{"id":"65630048aa7d07ce5ca28efc","title":"Pháp Y Tần Minh: Bản Hoà Tấu Trong Mưa","origin_name":"Doctor Qin Ming: Rain Killer","slug":"phap-y-tan-minh-ban-hoa-tau-trong-mua","_from_supabase":true,"year":"2023","type":"single","genre":[{"name":"Bí ẩn","slug":"bi-an"}],"country":[{"name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","modified":"2026-03-31T08:24:52.84+00:00","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Pháp Y Tần Minh Bản Hoà Tấu Trong Mưa","link_embed":"https://vip.opstream16.com/share/f73ebfc1b82481a8da059822d6ba1d10","link_m3u8":"https://vip.opstream16.com/20231126/38113_e636b4bd/index.m3u8"}]}],"description":"Câu chuyện miêu tả về một phụ nữ dịu dàng tên là Triệu Thiên Tuyết, có cuộc hôn nhân viên mãn và một người chồng hoàn hảo. Tuy nhiên, gần đây, chồng cô, Trịnh Trực, tuyên bố rằng anh bị cuốn vào những hiện tượng siêu nhiên không thể hiểu được, liên quan đến cái chết của một người tên là Tôn Tiểu Vũ, người đã tự treo cổ trước cửa nhà của Trịnh Trực cách đây một tuần. Sau đó, tại một ngôi nhà tang lễ ngoại ô, một xác chết bất ngờ biến mất, và nghi phạm đã được xác định là ông Xu Lệ Bình, một cựu nhân viên của nhà tang lễ. Sau đó, dân địa phương báo cáo về việc phát hiện một xác chết bị đốt cháy ở trong khu rừng ngoại ô thành phố. Trình Thanh Minh, một chuyên viên phân tích của cảnh sát, tiến hành khám nghiệm thi thể và xác minh danh tính, và kết quả cho thấy đó chính là Tôn Tiểu Vũ, người đã tự treo cổ trước cửa nhà Trịnh Trực. Các dấu vết cũng dẫn tới mẹ của Trịnh Trực, bà Từ Lệ Bình.","tmdb_id":1195423,"_supabaseOriginalSlug":"phap-y-tan-minh-ban-hoa-tau-trong-mua","_supabaseExportEpisodesOnly":false,"_id":"65630048aa7d07ce5ca28efc","time":"77 Phút","tmdb":{"type":"movie","id":"1195423","season":null,"vote_average":0,"vote_count":0},"_image_preserved":true},{"id":"656307c0aa7d07ce5ca2a282","title":"Tứ Yêu Quan Kì Án","origin_name":"The Case of the Four Demon Coffins","slug":"tu-yeu-quan-ki-an","_from_supabase":true,"year":"2023","type":"single","genre":[{"name":"Chính kịch","slug":"chinh-kich"},{"name":"Bí ẩn","slug":"bi-an"}],"country":[{"name":"Trung Quốc","slug":"trung-quoc"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","modified":"2026-03-31T14:11:25.78+00:00","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Tứ Yêu Quan Kì Án","link_embed":"https://vip.opstream16.com/share/a508f09b3bcd2ddcf6bc51274d38c997","link_m3u8":"https://vip.opstream16.com/20231126/38114_be3b80f8/index.m3u8"}]}],"description":"<p>Giai đoạn cuối triều nhà Thanh, đầu thời kì Trung Hoa Dân Quốc, cuộc sống người dân đầy biến động và bất ổn. Những băng đảng tội phạm và quân chủ thống trị hoành hành. Tại thị trấn nhỏ phía Tây Bắc có 